    board.setVar("seat_" + id + "_public_view", view);
    return text + "\n\n当前公开焦点:\n" + focus + "\n\n公开角色视图:\n" + view + "\n\n公开记忆:\n" + memory + "\n\n近期历史:\n" + history;
  }
  function seatPrivateCtx(id, text) {
