      const seen = {};
      for (const name of nodeNames) seen[name] = true;
      const msgs = board.channel(board.MAIN_CHANNEL) || [];
      return msgs.map(function(msg) {
        const parts = Array.isArray(msg.parts) ? msg.parts : [];
        let node = "";
        const text = parts.map(function(part) {
