const state = board.getVar("werewolf_game_state") || {};
const day = Number(state.day || 0);
let progress = board.getVar("werewolf_day_open_progress") || {};
if (Number(progress.day || -1) !== day || !Array.isArray(progress.spoken)) {
  progress = { day: day, spoken: [] };
}
const spoken = progress.spoken.map(Number);
const alive = {};
for (const id of state.alive || []) alive[String(Number(id))] = true;
let next = "";
for (const id of [1, 2]) {
  if (alive[String(id)] && spoken.indexOf(id) < 0) {
    next = String(id);
    spoken.push(id);
    break;
  }
}
progress.spoken = spoken;
board.setVar("werewolf_day_open_progress", progress);
board.setVar("werewolf_day_open_speaker", next);

